    /**
     * @method
     * @name alpaca#fetchTickers
     * @description fetches price tickers for multiple markets, statistical information calculated over the past 24 hours for each market
     * @see https://docs.alpaca.markets/reference/cryptosnapshots-1
     * @param {string[]} symbols unified symbols of the markets to fetch tickers for
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.loc] crypto location, default: us
     * @returns {object} a dictionary of [ticker structures]{@link https://docs.ccxt.com/?id=ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTickers(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(symbols, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchTickers() requires a symbols argument")) ;
            }
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            symbols = this.marketSymbols(symbols);
            Object loc = this.safeString(parameters, "loc", "us");
            Object ids = this.marketIds(symbols);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbols", String.join((String)",", (java.util.List<String>)ids) );
                put( "loc", loc );
            }};
            parameters = this.omit(parameters, "loc");
            Object response = (this.marketPublicGetV1beta3CryptoLocSnapshots(this.extend(request, parameters))).join();
            //
            //     {
            //         "snapshots": {
            //             "BTC/USD": {
            //                 "dailyBar": {
            //                     "c": 69403.554,
            //                     "h": 69609.6515,
            //                     "l": 69013.26,
            //                     "n": 9,
            //                     "o": 69536.7,
            //                     "t": "2024-11-01T05:00:00Z",
            //                     "v": 0.210809181,
            //                     "vw": 69327.655393908
            //                 },
            //                 "latestQuote": {
            //                     "ap": 69424.19,
            //                     "as": 0.68149,
            //                     "bp": 69366.086,
            //                     "bs": 0.68312,
            //                     "t": "2024-11-01T08:31:41.880246926Z"
            //                 },
            //                 "latestTrade": {
            //                     "i": 5272941104897543146,
            //                     "p": 69416.9,
            //                     "s": 0.014017324,
            //                     "t": "2024-11-01T08:14:28.245088803Z",
            //                     "tks": "B"
            //                 },
            //                 "minuteBar": {
            //                     "c": 69403.554,
            //                     "h": 69403.554,
            //                     "l": 69399.125,
            //                     "n": 0,
            //                     "o": 69399.125,
            //                     "t": "2024-11-01T08:30:00Z",
            //                     "v": 0,
            //                     "vw": 0
            //                 },
            //                 "prevDailyBar": {
            //                     "c": 69515.1415,
            //                     "h": 72668.837,
            //                     "l": 68796.85,
            //                     "n": 129,
            //                     "o": 72258.9,
            //                     "t": "2024-10-31T05:00:00Z",
            //                     "v": 2.217683307,
            //                     "vw": 70782.6811608144
            //                 }
            //             },
            //         }
            //     }
            //
            Object results = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object snapshots = this.safeDict(response, "snapshots", new java.util.HashMap<String, Object>() {{}});
            Object marketIds = Helpers.objectKeys(snapshots);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marketIds)); i++)
            {
                Object marketId = Helpers.GetValue(marketIds, i);
                Object market = this.safeMarket(marketId);
                Object entry = this.safeDict(snapshots, marketId);
                Object dailyBar = this.safeDict(entry, "dailyBar", new java.util.HashMap<String, Object>() {{}});
                Object prevDailyBar = this.safeDict(entry, "prevDailyBar", new java.util.HashMap<String, Object>() {{}});
                Object latestQuote = this.safeDict(entry, "latestQuote", new java.util.HashMap<String, Object>() {{}});
                Object latestTrade = this.safeDict(entry, "latestTrade", new java.util.HashMap<String, Object>() {{}});
                Object datetime = this.safeString(latestQuote, "t");
                Object ticker = this.safeTicker(new java.util.HashMap<String, Object>() {{
                    put( "info", entry );
                    put( "symbol", Helpers.GetValue(market, "symbol") );
                    put( "timestamp", AlpacaCore.this.parse8601(datetime) );
                    put( "datetime", datetime );
                    put( "high", AlpacaCore.this.safeString(dailyBar, "h") );
                    put( "low", AlpacaCore.this.safeString(dailyBar, "l") );
                    put( "bid", AlpacaCore.this.safeString(latestQuote, "bp") );
                    put( "bidVolume", AlpacaCore.this.safeString(latestQuote, "bs") );
                    put( "ask", AlpacaCore.this.safeString(latestQuote, "ap") );
                    put( "askVolume", AlpacaCore.this.safeString(latestQuote, "as") );
                    put( "vwap", AlpacaCore.this.safeString(dailyBar, "vw") );
                    put( "open", AlpacaCore.this.safeString(dailyBar, "o") );
                    put( "close", AlpacaCore.this.safeString(dailyBar, "c") );
                    put( "last", AlpacaCore.this.safeString(latestTrade, "p") );
                    put( "previousClose", AlpacaCore.this.safeString(prevDailyBar, "c") );
                    put( "change", null );
                    put( "percentage", null );
                    put( "average", null );
                    put( "baseVolume", AlpacaCore.this.safeString(dailyBar, "v") );
                    put( "quoteVolume", AlpacaCore.this.safeString(dailyBar, "n") );
                }}, market);
                ((java.util.List<Object>)results).add(ticker);
            }
            return this.filterByArray(results, "symbol", symbols);
        });

    }

    public Object generateClientOrderId(Object parameters)
    {
        Object clientOrderIdprefix = this.safeString(this.options, "clientOrderId");
        Object uuid = this.uuid();
        Object parts = Helpers.split(uuid, "-");
        Object random_id = String.join((String)"", (java.util.List<String>)parts);
        Object defaultClientId = this.implodeParams(clientOrderIdprefix, new java.util.HashMap<String, Object>() {{
            put( "id", random_id );
        }});
        Object clientOrderId = this.safeString(parameters, "clientOrderId", defaultClientId);
        return clientOrderId;
    }

