    /**
     * @method
     * @name alpaca#editOrder
     * @description edit a trade order
     * @see https://docs.alpaca.markets/reference/patchorderbyorderid-1
     * @param {string} id order id
     * @param {string} [symbol] unified symbol of the market to create an order in
     * @param {string} [type] 'market', 'limit' or 'stop_limit'
     * @param {string} [side] 'buy' or 'sell'
     * @param {float} [amount] how much of the currency you want to trade in units of the base currency
     * @param {float} [price] the price for the order, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.triggerPrice] the price to trigger a stop order
     * @param {string} [params.timeInForce] for crypto trading either 'gtc' or 'ioc' can be used
     * @param {string} [params.clientOrderId] a unique identifier for the order, automatically generated if not sent
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> editOrder(Object id, Object symbol2, Object type, Object side, Object... optionalArgs)
    {
        final Object symbol3 = symbol2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object symbol = symbol3;
            Object amount = Helpers.getArg(optionalArgs, 0, null);
            Object price = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "order_id", id );
            }};
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
            }
            if (Helpers.isTrue(!Helpers.isEqual(amount, null)))
            {
                Helpers.addElementToObject(request, "qty", this.amountToPrecision(symbol, amount));
            }
            Object triggerPrice = this.safeString2(parameters, "triggerPrice", "stop_price");
            if (Helpers.isTrue(!Helpers.isEqual(triggerPrice, null)))
            {
                Helpers.addElementToObject(request, "stop_price", this.priceToPrecision(symbol, triggerPrice));
                parameters = this.omit(parameters, "triggerPrice");
            }
            if (Helpers.isTrue(!Helpers.isEqual(price, null)))
            {
                Helpers.addElementToObject(request, "limit_price", this.priceToPrecision(symbol, price));
            }
            Object timeInForce = null;
            var timeInForceparametersVariable = this.handleOptionAndParams(parameters, "editOrder", "timeInForce", "gtc");
            timeInForce = ((java.util.List<Object>) timeInForceparametersVariable).get(0);
            parameters = ((java.util.List<Object>) timeInForceparametersVariable).get(1);
            if (Helpers.isTrue(!Helpers.isEqual(timeInForce, null)))
            {
                Helpers.addElementToObject(request, "time_in_force", timeInForce);
            }
            Helpers.addElementToObject(request, "client_order_id", this.generateClientOrderId(parameters));
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("clientOrderId")));
            Object response = (this.traderPrivatePatchV2OrdersOrderId(this.extend(request, parameters))).join();
            return this.parseOrder(response, market);
        });

    }

    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        //    {
        //        "id":"6ecfcc34-4bed-4b53-83ba-c564aa832a81",
        //        "client_order_id":"ccxt_1c6ceab0b5e84727b2f1c0394ba17560",
        //        "created_at":"2022-06-14T13:59:30.224037068Z",
        //        "updated_at":"2022-06-14T13:59:30.224037068Z",
        //        "submitted_at":"2022-06-14T13:59:30.221856828Z",
        //        "filled_at":null,
        //        "expired_at":null,
        //        "canceled_at":null,
        //        "failed_at":null,
        //        "replaced_at":null,
        //        "replaced_by":null,
        //        "replaces":null,
        //        "asset_id":"64bbff51-59d6-4b3c-9351-13ad85e3c752",
        //        "symbol":"BTCUSD",
        //        "asset_class":"crypto",
        //        "notional":null,
        //        "qty":"0.01",
        //        "filled_qty":"0",
        //        "filled_avg_price":null,
        //        "order_class":"",
        //        "order_type":"limit",
        //        "type":"limit",
        //        "side":"buy",
        //        "time_in_force":"day",
        //        "limit_price":"14000",
        //        "stop_price":null,
        //        "status":"accepted",
        //        "extended_hours":false,
        //        "legs":null,
        //        "trail_percent":null,
        //        "trail_price":null,
        //        "hwm":null,
        //        "commission":"0.42",
        //        "source":null
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(order, "symbol");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object alpacaStatus = this.safeString(order, "status");
        Object status = this.parseOrderStatus(alpacaStatus);
        Object feeValue = this.safeString(order, "commission");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeValue, null)))
        {
            final Object finalFeeValue = feeValue;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeValue );
                put( "currency", "USD" );
            }};
        }
        Object orderType = this.safeString(order, "order_type");
        if (Helpers.isTrue(!Helpers.isEqual(orderType, null)))
        {
            if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(orderType, "limit"), 0)))
            {
                // might be limit or stop-limit
                orderType = "limit";
            }
        }
        Object datetime = this.safeString(order, "submitted_at");
        Object timestamp = this.parse8601(datetime);
        final Object finalOrderType = orderType;
        final Object finalFee = fee;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", AlpacaCore.this.safeString(order, "id") );
            put( "clientOrderId", AlpacaCore.this.safeString(order, "client_order_id") );
            put( "timestamp", timestamp );
            put( "datetime", datetime );
            put( "lastTradeTimeStamp", null );
            put( "status", status );
            put( "symbol", symbol );
            put( "type", finalOrderType );
            put( "timeInForce", AlpacaCore.this.parseTimeInForce(AlpacaCore.this.safeString(order, "time_in_force")) );
            put( "postOnly", null );
            put( "side", AlpacaCore.this.safeString(order, "side") );
            put( "price", AlpacaCore.this.safeNumber(order, "limit_price") );
            put( "triggerPrice", AlpacaCore.this.safeNumber(order, "stop_price") );
            put( "cost", null );
            put( "average", AlpacaCore.this.safeNumber(order, "filled_avg_price") );
            put( "amount", AlpacaCore.this.safeNumber(order, "qty") );
            put( "filled", AlpacaCore.this.safeNumber(order, "filled_qty") );
            put( "remaining", null );
            put( "trades", null );
            put( "fee", finalFee );
            put( "info", order );
        }}, market);
    }

    public Object parseOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "pending_new", "open" );
            put( "accepted", "open" );
            put( "new", "open" );
            put( "partially_filled", "open" );
            put( "activated", "open" );
            put( "filled", "closed" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object parseTimeInForce(Object timeInForce)
    {
        Object timeInForces = new java.util.HashMap<String, Object>() {{
            put( "day", "Day" );
        }};
        return this.safeString(timeInForces, timeInForce, timeInForce);
    }

