    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades
        //
        //   {
        //       "t":"2022-06-14T05:00:00.027869Z",
        //       "x":"CBSE",
        //       "p":"21942.15",
        //       "s":"0.0001",
        //       "tks":"S",
        //       "i":"355681339"
        //   }
        //
        // fetchMyTrades
        //
        //     {
        //         "id": "20221228071929579::ca2aafd0-1270-4b56-b0a9-85423b4a07c8",
        //         "activity_type": "FILL",
        //         "transaction_time": "2022-12-28T12:19:29.579352Z",
        //         "type": "fill",
        //         "price": "67.31",
        //         "qty": "0.07",
        //         "side": "sell",
        //         "symbol": "LTC/USD",
        //         "leaves_qty": "0",
        //         "order_id": "82eebcf7-6e66-4b7e-93f8-be0df0e4f12e",
        //         "cum_qty": "0.07",
        //         "order_status": "filled",
        //         "swap_rate": "1"
        //     },
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString2(trade, "S", "symbol");
        Object symbol = this.safeSymbol(marketId, market);
        Object datetime = this.safeString2(trade, "t", "transaction_time");
        Object timestamp = this.parse8601(datetime);
        Object alpacaSide = this.safeString(trade, "tks");
        Object side = this.safeString(trade, "side");
        if (Helpers.isTrue(Helpers.isEqual(alpacaSide, "B")))
        {
            side = "buy";
        } else if (Helpers.isTrue(Helpers.isEqual(alpacaSide, "S")))
        {
            side = "sell";
        }
        Object priceString = this.safeString2(trade, "p", "price");
        Object amountString = this.safeString2(trade, "s", "qty");
        final Object finalSide = side;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", AlpacaCore.this.safeString2(trade, "i", "id") );
            put( "timestamp", timestamp );
            put( "datetime", AlpacaCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "order", AlpacaCore.this.safeString(trade, "order_id") );
            put( "type", null );
            put( "side", finalSide );
            put( "takerOrMaker", "taker" );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", null );
            put( "fee", null );
        }}, market);
    }

