    public java.util.concurrent.CompletableFuture<Object> fetchTransactionsHelper(Object type2, Object code2, Object since, Object limit, Object parameters)
    {
        final Object type3 = type2;
        final Object code3 = code2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object code = code3;
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object currency = null;
            if (Helpers.isTrue(!Helpers.isEqual(code, null)))
            {
                currency = this.currency(code);
            }
            Object response = (this.traderPrivateGetV2WalletsTransfers(parameters)).join();
            //
            //     {
            //         "id": "e27b70a6-5610-40d7-8468-a516a284b776",
            //         "tx_hash": null,
            //         "direction": "OUTGOING",
            //         "amount": "20",
            //         "usd_value": "19.99856",
            //         "chain": "ETH",
            //         "asset": "USDT",
            //         "from_address": "0x123930E4dCA196E070d39B60c644C8Aae02f23",
            //         "to_address": "0x1232c0925196e4dcf05945f67f690153190fbaab",
            //         "status": "PROCESSING",
            //         "created_at": "2024-11-07T02:39:01.775495Z",
            //         "network_fee": "4",
            //         "fees": "0.1"
            //     }
            //
            Object results = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(response)); i++)
            {
                Object entry = Helpers.GetValue(response, i);
                Object direction = this.safeString(entry, "direction");
                if (Helpers.isTrue(Helpers.isEqual(direction, type)))
                {
                    ((java.util.List<Object>)results).add(entry);
                } else if (Helpers.isTrue(Helpers.isEqual(type, "BOTH")))
                {
                    ((java.util.List<Object>)results).add(entry);
                }
            }
            return this.parseTransactions(results, currency, since, limit, parameters);
        });

    }

